INSERT INTO questions (exam_id, subject_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668', '637bf719-8dde-4035-946c-4242372328e2', 2023, 'Paper-II', 'Consider the following statements related to geometric design of highways and choose the correct option. Statements: 1. As a compromise and from practical considerations, it is suggested that the super-elevation should be provided to fully counteract the centrifugal force due to 95% of the design speed. 2. The ratio of the centrifugal force to the weight of the vehicle is known as centrifugal ratio.', 'Statement 1 is correct and statement 2 is incorrect', 'Statement 1 is incorrect and statement 2 is correct', 'Both Statement 1 & 2 are correct', 'Both Statement 1 & 2 are incorrect', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1', 2023, 'Paper-II', 'Identify the type of soil which effervesce when tested with weak hydrochloric acid.', 'Expansive Clay', 'Bentonite', 'Diatomaceous Earth', 'Calcareous Soil', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1', 2023, 'Paper-II', 'Choose the most relevant consistency type for the soil with following description: 1. Consistency Index = 1.27 2. Unconfined compressive strength = 450 kN/m².', 'Stiff', 'Medium', 'Hard', 'Soft', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1', 2023, 'Paper-II', 'Identify whether the following statements are correct or incorrect with respect to compaction of soil. Statements: 1. The heavier compaction decreases the maximum dry density of the soil but increases the optimum water content. 2. In compaction curve, 10% air content line and 90% saturation line are identical.', 'Statement 1 is correct and statement 2 is incorrect', 'Statement 1 is incorrect and statement 2 is correct', 'Both Statement 1 & 2 are correct', 'Both Statement 1 & 2 are incorrect', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1', 2023, 'Paper-II', 'Choose the correct statement(s) related to ultimate bearing capacity of a strip footing on cohesive soils. (i) It remains constant with increase in width of footing. (ii) It increases with increase in width of footing. (iii) It decreases with increase in width of footing.', 'Only (i)', 'Both (i) and (ii)', 'Only (iii)', 'Both (i) and (iii)', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1', 2023, 'Paper-II', 'Match the items under List 1 (Group Symbol) with those under List 2 (Typical Name) in Indian Standard Classification system and choose the correct option. P. ML Q. OL R. CH S. Pt', 'P-4,Q-1,R-2,S-3', 'P-2,Q-4,R-1,S-3', 'P-3,Q-1,R-4,S-2', 'P-4,Q-3,R-1,S-2', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1', 2023, 'Paper-II', 'Which of the following is the correctly matched pair of type of soil and its range of coefficient of permeability (mm/sec)?', 'Clean Gravel - 10⁻⁴ to 10⁻²', 'Fine Sand - 10⁻² to 10⁻⁴', 'Dense Silt - 10⁻⁵ to 10⁻⁴', 'Silty Clay - 10⁻² to 10⁻¹', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c39bc91d-4a88-42c6-b1f7-ae4fc2b0dba1', 2023, 'Paper-II', 'Arrange the following types of soil/rock in decreasing order of their safe bearing capacity. A. Compact and Dry medium sand B. Laminated Rock C. Hard or Stiff Clay D. Residual Deposits of Shattered and broken rocks', 'B, A, C, D', 'D, C, B, A', 'D, A, C, B', 'B, D, C, A', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'A RCC continuous beam has 2.5m of effective span. The beam will be deemed to be a deep beam if', 'The overall depth of beam is equal to 750mm', 'The overall depth of beam is equal to 500mm', 'The effective depth of beam is equal to 600mm', 'The overall depth of beam is equal to 1200mm', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'Which of the following is/are the disadvantage(s) of the Working Stress Method in RCC Design? 1. The working stress method fails to discriminate between different types of load that act simultaneously but have different uncertainties. 2. The actual factor of safety is not known in this method of design.', 'Statement 1 is correct and statement 2 is incorrect', 'Statement 1 is incorrect and statement 2 is correct', 'Both Statement 1 & 2 are correct', 'Both Statement 1 & 2 are incorrect', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'According to IS : 456 - 2000, in limit state method of design of RCC structures, which of the following is the mismatched pair of environmental conditions & minimum grade of reinforced concrete required?', 'Very Severe - M35', 'Mild - M15', 'Extreme - M40', 'Moderate - M25', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'Arrange the following in the increasing order of their striking/removal period of formwork for different elements of RCC structures. A. Props to beam spanning over 6m. B. Vertical formwork to walls. C. Props to slabs spanning over 4.5m. D. Soffit formwork to slabs (props to be re-fixed immediately after removal of formwork)', 'B, A, C, D', 'D, C, B, A', 'D, A, C, B', 'B, D, C, A', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'For outstanding element of compression flange of Rolled Steel I- Section, if b/t_f is < 9.4ε, then section is classified as -', 'Compact', 'Semi-Compact', 'Plastic', 'Slender', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'In which of the following situation, the spot welding is used?', 'when two plates are placed one below the other', 'when two plates are placed one butting against the other', 'when two plates are placed one next to other', 'when two plates are placed at right angles to each other', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'Consider the following statements related to steel built- up column design according to IS 800: 2007, and choose the correct option. Statements: 1. In bolted/riveted construction, the effective length of lacing bars for the determination of the design strength shall be taken as the length between the inner end fastener of the bars for single lacing system. 2. In bolted/riveted construction, the minimum width of lacing bars shall be five times the nominal diameter of the end bolt/rivet.', 'Both statements are true.', 'Statement 1 is false and statement 2 is true.', 'Both statements are false.', 'Statement 2 is false and statement 1 is true.', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'Which of the following statements is INCORRECT with respect to the design of steel roof trusses? Statements: 1. If the roof slope is 20°, the snow load may be neglected. 2. One of the most critical load on an industrial steel building is the wind load. 3. The dead loads of the truss include the dead load of roofing materials, purlins, trusses and bracing system.', 'Only 1', 'Only 2', 'Only 3', 'Both 2 & 3', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'e7eaeaa0-d839-4490-abed-c71027b61424', 2023, 'Paper-II', 'According to IS : 800 - 2007, which of the following is the correctly matched pair of ''thickness of thicker plate'' and minimum size of fillet weld''?', '0 mm to 10mm - 2mm', '11 mm to 20mm - 4mm', '21 mm to 32mm - 6mm', '33 mm to 50mm - 12mm', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '64289b52-861b-4a49-9286-4c4196691af7', 2023, 'Paper-II', 'Identify the INCORRECT method for reclamation of uncultivable agriculture land due to waterlogging and salinity.', 'Leaching', 'Application of 1 to 5 percent solution of sodium chloride chemical', 'Adopting rice cultivation', 'Drainage and lowering of water table', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '64289b52-861b-4a49-9286-4c4196691af7', 2023, 'Paper-II', 'Which of the following does represent the irrigating capacity of a unit quantity of water?', 'Base Period', 'Field Capacity', 'Delta', 'Duty', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '64289b52-861b-4a49-9286-4c4196691af7', 2023, 'Paper-II', 'A crop requires a total depth of 100 cm of water for a base period of 200 days, determine the duty of irrigating water.', '17.28 hectares/cumec', '14.32 hectares/cumec', '1728 hectares/cumec', '1432 hectares/cumec', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '64289b52-861b-4a49-9286-4c4196691af7', 2023, 'Paper-II', 'Which of the following is/are the correct remedies to prevent the rupture of weir floor due to suction caused by standing wave? Statements: 1. Providing additional thickness of floor to counterbalance the extra pressure due to the standing wave. 2. Constructing the floor thickness in one concrete mass instead of masonry layers.', 'Both statements are correct.', 'Statement 1 is incorrect and statement 2 is correct.', 'Both statements are incorrect.', 'Statement 2 is incorrect and statement 1 is correct.', 1, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '64289b52-861b-4a49-9286-4c4196691af7', 2023, 'Paper-II', 'Which of the following is/are the disadvantage(s) of Tipping Bucket Rain Gauge? Statements: 1. The Tipping Bucket Rain Gauge is most suitable for measuring snow. 2. The Tipping Bucket Rain Gauge does not give accurate results in the case of intense rainfall because some of the rain, which falls during the period when the bucket is emptying, is not measured. 3. The record consists of a series of steps and not a conventional smooth mass curve required for precipitation analysis.', 'Only 1', 'Only 2', 'Only 3', '2 and 3 only', 4, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '64289b52-861b-4a49-9286-4c4196691af7', 2023, 'Paper-II', 'Arrange the following steps for design of flood control project in the correct chronological order (from the earliest to the latest). A. Select the flood control measure or a combination of measures which offers the desired protection at a minimum cost. B. Perform the economic analysis of the benefits and costs to determine whether the selected project is economical viable. C. Estimate the project design flood and determine the flood characteristics of the given area. D. Design the flood control works for different alternatives of flood control measures so that the cost estimates may be made and their effects on the flood discharge may be estimated.', 'A, B, C, D', 'C, D, A, B', 'D, C, A, B', 'B, A, C, D', 2, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', '64289b52-861b-4a49-9286-4c4196691af7', 2023, 'Paper-II', 'Match the items under List 1 (Basis of Classification of Canal) with those under List 2 (Type/Name of Canal) in Classification of Canals and choose the correct option. P. Canal Alignment Q. Functions of the canal R. Discharge & its relative importance S. Boundary surface of the canal', 'P-4,Q-1,R-2,S-3', 'P-2,Q-4,R-1,S-3', 'P-3,Q-1,R-4,S-2', 'P-4,Q-3,R-1,S-2', 3, NULL, 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668', 'c542f294-548d-4129-8d45-b3f75629dc1b', 2023, 'Paper-II', 'According to IS 10500: 2012, in absence of an alternate source, how much is the maximum permissible limit of ''colour'', for drinking water, provided that toxic substances are not suspected in the available water source?', '5 Hazen units', '5 NTU units', '15 NTU units', '15 Hazen units', 4, NULL, 'medium')
